import { motion } from 'framer-motion';
import { AnimatedSection } from '../components/AnimatedSection';
import { ArrowUpRight, Building } from 'lucide-react';

const locations = [
  {
    name: 'Koramangala',
    properties: 245,
    image: '/images/neighborhood-lake.jpg',
    description: 'Premium residential area',
  },
  {
    name: 'Whitefield',
    properties: 189,
    image: '/images/amenities-park.jpg',
    description: 'IT hub with modern homes',
  },
  {
    name: 'Indiranagar',
    properties: 156,
    image: '/images/lifestyle-lake.jpg',
    description: 'Upscale urban living',
  },
  {
    name: 'HSR Layout',
    properties: 203,
    image: '/images/spotlight-exterior.jpg',
    description: 'Family-friendly locality',
  },
];

export const Locations: React.FC = () => {
  return (
    <section id="locations" className="py-20 lg:py-32 bg-blueprint-blue blueprint-grid">
      <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
        {/* Header */}
        <AnimatedSection className="text-center mb-16">
          <span className="label-mono text-white/70 mb-4 block">
            Popular Locations
          </span>
          <h2 className="font-display text-3xl sm:text-4xl lg:text-5xl font-bold text-white mb-4">
            Explore Prime Neighborhoods
          </h2>
          <p className="text-white/70 text-lg max-w-2xl mx-auto">
            Discover properties in Bangalore&apos;s most sought-after locations, 
            each offering unique lifestyle benefits.
          </p>
        </AnimatedSection>

        {/* Locations Grid */}
        <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-6">
          {locations.map((location, index) => (
            <AnimatedSection key={location.name} delay={index * 0.1}>
              <motion.div
                className="group relative h-80 rounded-2xl overflow-hidden cursor-pointer"
                whileHover={{ scale: 1.02 }}
                transition={{ duration: 0.3 }}
              >
                {/* Background Image */}
                <img
                  src={location.image}
                  alt={location.name}
                  loading="lazy"
                  className="absolute inset-0 w-full h-full object-cover transition-transform duration-500 group-hover:scale-110"
                />
                
                {/* Overlay */}
                <div className="absolute inset-0 bg-gradient-to-t from-black/80 via-black/40 to-transparent" />
                
                {/* Content */}
                <div className="absolute inset-0 p-6 flex flex-col justify-end">
                  <div className="flex items-start justify-between">
                    <div>
                      <h3 className="font-display text-xl font-bold text-white mb-1">
                        {location.name}
                      </h3>
                      <p className="text-white/70 text-sm mb-3">
                        {location.description}
                      </p>
                      <div className="flex items-center gap-2 text-white/90">
                        <Building className="w-4 h-4" />
                        <span className="text-sm font-medium">
                          {location.properties} Properties
                        </span>
                      </div>
                    </div>
                    <motion.div
                      className="p-2 rounded-full bg-white/20 backdrop-blur-sm"
                      whileHover={{ scale: 1.1, backgroundColor: 'rgba(255,255,255,0.3)' }}
                    >
                      <ArrowUpRight className="w-5 h-5 text-white" />
                    </motion.div>
                  </div>
                </div>

                {/* Hover Border Effect */}
                <div className="absolute inset-0 rounded-2xl border-2 border-white/0 group-hover:border-white/20 transition-colors duration-300" />
              </motion.div>
            </AnimatedSection>
          ))}
        </div>

        {/* Stats Bar */}
        <AnimatedSection delay={0.4}>
          <div className="mt-16 p-8 rounded-2xl bg-white/5 backdrop-blur-sm border border-white/10">
            <div className="grid grid-cols-2 md:grid-cols-4 gap-8 text-center">
              {[
                { value: '50+', label: 'Neighborhoods' },
                { value: '10K+', label: 'Properties' },
                { value: '5K+', label: 'Happy Families' },
                { value: '99%', label: 'Satisfaction' },
              ].map((stat) => (
                <div key={stat.label}>
                  <div className="font-display text-3xl sm:text-4xl font-bold text-white mb-1">
                    {stat.value}
                  </div>
                  <div className="text-white/60 text-sm">{stat.label}</div>
                </div>
              ))}
            </div>
          </div>
        </AnimatedSection>
      </div>
    </section>
  );
};

export default Locations;
