import { SmoothScroll } from './components/SmoothScroll';
import {
  NotchNavbar,
  Hero,
  Partners,
  PropertySearch,
  Locations,
  Features,
  Contact,
  Footer,
} from './sections';

function App() {
  return (
    <SmoothScroll>
      <div className="relative">
        <NotchNavbar />
        <main>
          <Hero />
          <Partners />
          <PropertySearch />
          <Locations />
          <Features />
          <Contact />
        </main>
        <Footer />
      </div>
    </SmoothScroll>
  );
}

export default App;
