import { useState } from 'react';
import { properties, Property } from '../data/properties';

const API_URL = 'https://api.sambanova.ai/v1/chat/completions';

export const useAIPropertySearch = () => {
  const [loading, setLoading] = useState(false);
  const [results, setResults] = useState<Property[]>([]);
  const [explanation, setExplanation] = useState<string>('');

  const searchProperties = async (query: string) => {
    const API_KEY = import.meta.env.VITE_SAMBANOVA_API_KEY;
    
    if (!API_KEY || API_KEY === 'your_api_key_here') {
      console.warn('VITE_SAMBANOVA_API_KEY placeholder or missing. Using demo mode.');
      setLoading(true);
      setTimeout(() => {
        const queryLower = query.toLowerCase();
        
        // Developer priority order
        const devPriority = ['embassy', 'godrej', 'assetz', 'brigade', 'lodha'];
        
        // Initial filtering
        let filtered = properties;
        
        // Budget check (crude local matching)
        if (queryLower.includes('under') || queryLower.includes('below')) {
          const match = queryLower.match(/(\d+(\.\d+)?)\s*(cr|lakh|l)/);
          if (match) {
            const limit = parseFloat(match[1]) * (match[3] === 'cr' ? 1 : 0.01);
            filtered = filtered.filter(p => p.priceValue <= limit);
          }
        }
        
        // Sort by developer priority if mentioned or just by preference
        filtered.sort((a, b) => {
          const aIndex = devPriority.indexOf(a.developer.toLowerCase().split(' ')[0]);
          const bIndex = devPriority.indexOf(b.developer.toLowerCase().split(' ')[0]);
          
          if (aIndex !== -1 && bIndex !== -1) return aIndex - bIndex;
          if (aIndex !== -1) return -1;
          if (bIndex !== -1) return 1;
          return 0;
        });

        // Finally filter by name if search was specific
        const finalResults = filtered.filter(p => 
          p.title.toLowerCase().includes(queryLower) || 
          p.location.toLowerCase().includes(queryLower) ||
          p.developer.toLowerCase().includes(queryLower) ||
          p.tag.toLowerCase().includes(queryLower)
        );

        setResults(finalResults.length > 0 ? finalResults.slice(0, 4) : filtered.slice(0, 4));
        setExplanation(`Demo Mode: Results prioritized by our recommendation engine (Top Developers: Embassy, Godrej, Assetz, Brigade, Lodha).`);
        setLoading(false);
      }, 1500);
      return;
    }

    setLoading(true);
    setResults([]);
    setExplanation('');

    try {
      const systemPrompt = `
          You are an AI Real Estate Expert for "Propertyfie". 
          Your priority is 100% RELEVANCE and TRUSTED DEVELOPER ORDER.
          
          Available Properties:
          ${JSON.stringify(properties, null, 2)}
          
          STRICT RULES:
          1. BUDGET FILTERING: The "priceValue" field is in Cr (Crores). If a user specifies a budget, EXCLUDE anything above it.
          2. DEVELOPER PRIORITIZATION: Regardless of user query, if multiple projects match the filters, prioritize them in this ORDINAL RANK:
             I.   Embassy Group
             II.  Godrej Properties
             III. Assetz Property
             IV.  Brigade Group
             V.   Lodha Group
          3. EXPLANATION: Justify the selection based on budget first, and then clearly mention that these are the top recommended developers for the given criteria.
          
          Format: {"propertyIds": [id1, id2...], "explanation": "..."}
        `;

      const response = await fetch(API_URL, {
        method: 'POST',
        headers: {
          'Authorization': `Bearer ${API_KEY}`,
          'Content-Type': 'application/json',
        },
        body: JSON.stringify({
          model: "Meta-Llama-3.1-8B-Instruct",
          messages: [
            { role: "system", content: systemPrompt },
            { role: "user", content: query }
          ],
          stream: true,
        }),
      });

      if (!response.ok) throw new Error(`API Error: ${response.statusText}`);

      const reader = response.body?.getReader();
      const decoder = new TextDecoder();
      let fullContent = '';

      if (reader) {
        while (true) {
          const { done, value } = await reader.read();
          if (done) break;

          const chunk = decoder.decode(value);
          const lines = chunk.split('\n');

          for (const line of lines) {
            if (line.startsWith('data: ')) {
              const dataStr = line.slice(6);
              if (dataStr === '[DONE]') break;
              
              try {
                const data = JSON.parse(dataStr);
                const content = data.choices[0]?.delta?.content || '';
                fullContent += content;
                
                // Try to parse partial JSON for explanation live
                // (This is tricky for JSON objects, so we'll just wait for the end or show a partial string)
              } catch (e) {
                // Ignore parse errors for incomplete chunks
              }
            }
          }
        }
      }

      // Final parse
      try {
        const jsonMatch = fullContent.match(/\{.*\}/s);
        if (jsonMatch) {
          const parsed = JSON.parse(jsonMatch[0]);
          setResults(properties.filter(p => parsed.propertyIds?.includes(p.id)));
          setExplanation(parsed.explanation || '');
        } else {
          // If not proper JSON, use the full content as explanation and default results
          setExplanation(fullContent);
          setResults(properties.slice(0, 3));
        }
      } catch (e) {
        setExplanation(fullContent);
        setResults(properties.slice(0, 3));
      }

    } catch (error) {
      console.error('Search failed:', error);
      setExplanation('Expert search failed. Showing featured properties.');
      setResults(properties.slice(0, 3));
    } finally {
      setLoading(false);
    }
  };

  return { searchProperties, loading, results, explanation };
};
